<?php
if(!defined("IN_ESOTALK"))exit;class forgotpassword extends Controller{var $view="forgotPassword.view.php";var $title="";var $errors=array();var $setPassword=false;function init(){global $language,$messages,$config;if($this->esoTalk->user)redirect("");$this->title=$language["Forgot your password"];if($hash=@$_GET["q2"]){$result=$this->esoTalk->db->query("SELECT memberId FROM {$config["tablePrefix"]}members WHERE resetPassword='$hash'");if(!$this->esoTalk->db->numRows($result))redirect("forgotPassword");list($memberId)=$this->esoTalk->db->fetchRow($result);$this->setPassword=true;if(isset($_POST["changePassword"])){$password=@$_POST["password"];$confirm=@$_POST["confirm"];if($error=validatePassword(@$_POST["password"]))$this->errors["password"]=$error;if($password!=$confirm)$this->errors["confirm"]="passwordsDontMatch";if(!count($this->errors)){$passwordHash=md5($config["salt"].$password);$this->esoTalk->db->query("UPDATE {$config["tablePrefix"]}members SET resetPassword=NULL, password='$passwordHash' WHERE memberId=$memberId");$this->esoTalk->message("passwordChanged",false);redirect("");}}}if(isset($_POST["email"])){$result=$this->esoTalk->db->query("SELECT memberId, name, email FROM {$config["tablePrefix"]}members WHERE email='{$_POST["email"]}'");if(!$this->esoTalk->db->numRows($result)){$this->esoTalk->message("emailDoesntExist");return;}list($memberId,$name,$email)=$this->esoTalk->db->fetchRow($result);$hash=md5(rand());$this->esoTalk->db->query("UPDATE {$config["tablePrefix"]}members SET resetPassword='$hash' WHERE memberId=$memberId");if(sendEmail($email,sprintf($language["emails"]["forgotPassword"]["subject"],$name),sprintf($language["emails"]["forgotPassword"]["body"],$name,$config["forumTitle"],$config["baseURL"].makeLink("forgot-password",$hash)))){$this->esoTalk->message("passwordEmailSent",false);redirect("");}}}}
